var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 메인 드라이브에 치명적인 손상.</color>","JPN":"<color=#ff3636>警告。メインドライブに致命的な損傷。</color>","ENG":"<color=#ff3636>Warning. Critical damage to the main drive.</color>","TWN":"<color=#ff3636>警告。主引擎遭到致命損壞。</color>"},"stage":{"bg":"YAKSHA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L7_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 범인류 이민선 시무르그 출력 저하 64%</color>","JPN":"<color=#ff3636>警告。汎人類移民船シムルグ出力低下64％。</color>","ENG":"<color=#ff3636>Warning. Exodus Fleet of Humankind Simurgh Output decreased to 64%.</color>","TWN":"<color=#ff3636>警告。人類移民船西摩格輸出下降64%</color>"},"stage":{"bg":"YAKSHA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L8_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 범인류 이민선 시무르그 지구 대기권에 돌입합니다. </color>","JPN":"<color=#ff3636>警告。汎人類移民船シムルグ、地球大気圏に突入します。</color>","ENG":"<color=#ff3636>Warning. Exodus Fleet of Humankind Simurgh entering Earth's atmosphere.</color>","TWN":"<color=#ff3636>警告。人類移民船西摩格進入地球大氣層。</color>"},"stage":{"bg":"YAKSHA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L9_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 표면 온도 급상승. 이민선 프레임에 심각한 손상 감지.</color>","JPN":"<color=#ff3636>警告。表面温度急上昇。移民船フレームに深刻な損傷感知。</color>","ENG":"<color=#ff3636>Warning. Surface temperature rapidly increasing. Detecting severe damage to Exodus Fleet's frame.</color>","TWN":"<color=#ff3636>警告。表面溫度迅速升高。檢測到移民船軀殼嚴重損壞。</color>"},"stage":{"bg":"YAKSHA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L10_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 경고. 경고. 경고. 경고────────────!</color>","JPN":"<color=#ff3636>警告。警告。警告。警告。警告────────────！</color>","ENG":"<color=#ff3636>Warning. Warning. Warning. Warning. Warning!!</color>","TWN":"<color=#ff3636>警告。警告。警告。警告。警告────────────！</color>"},"stage":{"bg":"YAKSHA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L11_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>이민선 시무르그. 보조 동력으로 전환. 항행 목표를 변경합니다.</color>","JPN":"<color=#ff3636>移民船シムルグ。補助動力に転換。航行目標を変更します。</color>","ENG":"<color=#ff3636>Exodus Fleet Simurgh. Switching to backup power. Changing navigation objective.</color>","TWN":"<color=#ff3636>移民船西摩格切換至輔助動力。即將更改航行目標。</color>"},"stage":{"bg":"YAKSHA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"메이즈 전대장님! 우주로부터 통신이 잡혔습니다!","JPN":"メイズ戦隊長！　宇宙から通信を捉えました！","ENG":"Maze Commander! We're picking up a transmission from space!","TWN":"梅茲戰隊長！我們收到了來自太空的通訊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스인가! 당장 연결해!","JPN":"アリスか！　今すぐ繋げろ！","ENG":"Is it Alice?! Connect me immediately!","TWN":"是艾莉絲！立即連接！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"지휘부에! 앨리스다!","JPN":"司令部！　アリスだ！","ENG":"Headquarters! This is Alice!","TWN":"指揮部！我是艾莉絲！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 전대장! 자네 괜찮은가!!","JPN":"アリス戦隊長！　君、大丈夫なのか！！","ENG":"Commander Alice!! Are you all right?!","TWN":"艾莉絲戰隊長！你還好嗎！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"들리나! 아무나 대답해!","JPN":"聞こえるか！　誰でもいいから返事をしろ！","ENG":"Do you hear me?! Can anyone say something?!","TWN":"能聽得到嗎？請回答！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"녀석의 동력원은 파괴했어! 이면세계로 도주하기 전에 어떻게든 막아야 돼!","JPN":"やつの動力源は破壊した！　裏世界に逃走する前に、なんとかして止めないと！","ENG":"Her power source is destroyed! We have to stop her before she retreats to the Counterside!","TWN":"我已經摧毀了它的動力源！在它撤回異界之前，一定要阻止它！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"녀석은 사도……","JPN":"やつは使徒……","ENG":"She's an Apostle–","TWN":"那傢伙是使徒……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……죽게 될거야. 그러니까!","JPN":"……死ぬことになる。だから！","ENG":"–are going to die!","TWN":"……會死的。所以！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"우주 잔류 침식파 때문인가, 수신 감도가 좋지 않아.","JPN":"宇宙残留侵食波のせいか、受信感度がよくない。","ENG":"Is it because of the Corruption rays remaining in space? The signal's weak.","TWN":"喂？可能是因為空間殘留的侵蝕波，接收靈敏度不好！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지휘부다! 당장 복귀해, 전대장! 혼자 달려들어서 뭘 어떻게 하려고!","JPN":"司令部からの指示だ！　直ちに復帰しろ、戦隊長！　一人で飛び込んでどうするつもりだ！","ENG":"This is Headquarters! Return to base immediately, Commander! Rushing in there alone won't achieve anything!","TWN":"這裡是指揮部！馬上返航，戰隊長！你自己一個人能幹什麼！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"구조선을 보내겠다 그러니까……!","JPN":"救助船を送る。だから……！","ENG":"I'm sending a rescue ship, so...!","TWN":"我會派出救援艦船，所以……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……차원 도약 직전에 궤도를 틀어버리면 돼!","JPN":"……次元跳躍の直前に軌道を曲げさせればいい！","ENG":"–change the trajectory right before the dimension jump!","TWN":"……在次元躍遷前改變軌道就可以……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 소리 하는 거야! 적 함선이 차원 도약을 하고 있다는 뜻인가!","JPN":"何を言っている！　敵の艦船が次元跳躍しているということか？","ENG":"What are you talking about?! Is the enemy ship getting ready to make a dimension jump?!","TWN":"你在說什麼！你是說敵人的艦船正在進行次元躍遷嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……기동 전이라면 분명 타격을 가할 수 있어!","JPN":"……起動前ならきっとダメージを与えられる！","ENG":"–I know that thing will take damage if I strike before it activates!","TWN":"……如果搶在啟動之前，一定能造成傷害！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"거기에 휘말린 자네는! 단거리 공간 도약으로는 벗어날 수 없어 죽는다고!","JPN":"それに巻き込まれる君はどうなる！　短距離空間跳躍では抜け出せない！　死ぬぞ！","ENG":"But what if you get caught up in it? You won't get away with just a short-distance space jump! You'll get yourself killed!","TWN":"但你也會被捲入的！用近距空間跳耀沒辦法逃出來！會沒命的！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스! 앨리스 전대장!!","JPN":"アリス！　アリス戦隊長！！","ENG":"Alice?! Commander Alice!!","TWN":"艾莉絲！艾莉絲戰隊長！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"들리나!","JPN":"聞こえるか！","ENG":"Do you hear me?!","TWN":"聽得見嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……크윽!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳咳!"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"모네카! 당장, 차원함선에서 대기하고 있는 펜릴과 카멜롯에게 전달해!","JPN":"モネカ！　今すぐ次元艦船で待機しているフェンリルとキャメロットに伝えろ！","ENG":"Moneka! Deliver the news to Fenrir and Camelot who are waiting in the dimensional ship immediately!","TWN":"莫奈卡！立刻，將情況轉達給在次元艦船上待命的芬里爾和卡梅羅！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 전대장이 성공했다! 대기권 너머의 적 함선은 현재 도주 중!","JPN":"アリス戦隊長が成功した！　大気圏越しの敵艦船は現在逃走中！","ENG":"Commander Alice succeeded! The enemy ship beyond the atmosphere is currently attempting to flee!","TWN":"艾莉絲戰隊長成功了！大氣層外的艦船目前正在逃離！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"마침내 필하모닉 홀로 가는 길이 열렸다!","JPN":"ついにフィルハーモニーホールへの道が開けた！","ENG":"The path to Philharmonic Hall is finally open!","TWN":"通往管弦樂廳的路打開了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"반드시 그곳의 연합 전대를 구출하는 거다!","JPN":"必ず連合戦隊を救出するのだ！","ENG":"Go and rescue the coalition divisions there!","TWN":"我們必須救出那裡的聯合戰隊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"빌어먹을……! 뭐가 어떻게 된 거야……? 왜 대답이 없어……!?","JPN":"くそ……！　何がどうなってんだ……？　なんで返事がないんだよ……！？","ENG":"Dammit...! What's going on...? Why isn't anyone answering...?!","TWN":"可、可惡……到底怎麼回事……為什麼沒有回應……？！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"함선이……. 서서히 추락하고 있어…….","JPN":"艦船が……ゆっくり墜落している……","ENG":"The ship... it's slowly falling...","TWN":"艦船……正在墜落……"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"차원도약으로 도망치기 전에……. 반드시 파괴해야만 해……!","JPN":"次元跳躍で逃げる前に……必ず破壊しないと……！","ENG":"It must be destroyed... before it makes the dimension jump and gets away...!","TWN":"在它通過次元躍遷逃走之前……必須要毀掉它……！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"여기서 이 녀석을 놓치면 수많은 사람들이 죽게 될 거야……!!","JPN":"ここでこいつを逃せば、たくさんの人が死ぬことになるぞ……！！","ENG":"If I lose her now, countless people will be killed...!!","TWN":"如果放走它，很多人都會死去的……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"呃？"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>호위용 공간 도약 전투 단말 사출.</color>","JPN":"<color=#ff3636>護衛用空間跳躍戦闘端末射出。</color>","ENG":"<color=#ff3636>Space-jumping Escort Fighter deployed.</color>","TWN":"<color=#ff3636>彈出護衛型空間跳躍戰鬥體終端。</color>"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L13_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>이민선 시무르그 본체로부터 AI 추출.</color>","JPN":"<color=#ff3636>移民船シムルグ本体からAI抽出。</color>","ENG":"<color=#ff3636>Extracting AI from Exodus Fleet Simurgh.</color>","TWN":"<color=#ff3636>正在從移民船西摩格本體提取AI。</color>"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L14_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>……추출 완료.</color>","JPN":"<color=#ff3636>……抽出完了。</color>","ENG":"<color=#ff3636>...Extraction complete.</color>","TWN":"<color=#ff3636>……提取完畢。</color>"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L15_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>호위용 공간 도약 전투체에 AI 인스톨.</color>","JPN":"<color=#ff3636>護衛用空間跳躍戦闘体にAIをインストール。</color>","ENG":"<color=#ff3636>Installing AI to Space-jumping Escort Fighter.</color>","TWN":"<color=#ff3636>正在為空間跳躍戰鬥體安裝AI程式。</color>"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>이민선 본체로부터 외장 아베스타 드라이브 삽입.</color>","JPN":"<color=#ff3636>移民船本体から外装アヴェスター・ドライブ挿入。</color>","ENG":"<color=#ff3636>Injecting external Avesta Drive from Exodus Fleet.</color>","TWN":"<color=#ff3636>從移民船接入外部阿貝斯塔引擎。</color>"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L24_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"아베스타 드라이브 삽입 완료.","JPN":"アヴェスター・ドライブ挿入完了。","ENG":"Avesta Drive installation complete.","TWN":"阿貝斯塔引擎安裝成功。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"정화병기 엘부르즈 대검 사출","JPN":"浄化兵器アルボルズ大剣射出。","ENG":"Purification Weapon Alborz greatsword deployed.","TWN":"淨化兵器 艾爾布勒茲已部署。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"범인류 이민선단 호위용 공간 도약 전투체. 시무르그 활성화.","JPN":"汎人類移民船団護衛用、空間跳躍戦闘体。シムルグ活性化。","ENG":"Space-jumping Escort Fighter for Exodus Fleet of Humankind… Simurgh activated.","TWN":"護衛人類移民船隊的空間跳躍戰鬥體。西摩格啟動。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"기동 목적. 인류 선별.","JPN":"起動目的。人類選別。","ENG":"Purpose of activation: Select mankind.","TWN":"啟動目的。篩選人類。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장, 이건 또 뭐야? 함선으로 끝난 거 아니었어?","JPN":"くそ、なんだよこれ？　艦船で終わったんじゃないのかよ。","ENG":"Ugh, what's it now? The ship's not the end of it?","TWN":"該死，這又是什麼？艦船不是最後的敵人嗎？"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"제기랄, 야단났네……!!","JPN":"畜生、大変だ……！！","ENG":"Dammit, this isn't looking good...!!","TWN":"可惡，這下糟糕了……!!"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"인간. 당신에게서는 가능성이 느껴집니다.","JPN":"人間。あなたからは可能性を感じます。","ENG":"Human. I see possibilities in you.","TWN":"人類。我看到了你的潛力。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L34_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"무슨 헛소리야!","JPN":"何を戯けたことを！","ENG":"What are you talking about?!","TWN":"你在胡說些什麼！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"감탄. 환상종과 인간의 하이브리드.","JPN":"感嘆。幻想種と人間のハイブリッド。","ENG":"Surprised. A hybrid between a human and a Bygone.","TWN":"驚歎。夢幻品種與人類的混種。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"인간의 육체로 아베스타 드라이브의 반동을 두 번이나 견딘 것.","JPN":"あなたは人間の肉体でアヴェスター・ドライブの反動に二度も耐えた。","ENG":"Withstanding the recoil of Avesta Drive twice with a human body.","TWN":"你以人類的肉身承受了兩次阿貝斯塔引擎的反衝力。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"우리 선단에 보존된 인류 중에서는 없던 특징입니다.","JPN":"これはこの船団に保存された人類の中にはなかった特徴です。","ENG":"This is an unprecedented characteristic of any human preserved in our fleet.","TWN":"這是我們船隊中所保存下來的人類裡還沒有發現的特徵。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"따라서 특이성을 가진 개체로서 당신의 가치를 높게 책정…….","JPN":"よって、特異性を持つ個体としてあなたの価値を高く評価し……","ENG":"Thus, your assessment is valued high due to your uniqueness...","TWN":"因此，作為一個具有特異性的個體，你的評估價值已被高度重視……"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"경고. 지금부터 인류 선별에 대한 재심사를 시작하겠습니다.","JPN":"警告。今から人類選別についての再審査を開始します。","ENG":"Warning. A retrial on the selection of humanity will commence.","TWN":"警告。從現在開始，將對篩選人類重新進行審查。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊，哈啊……！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"야, 깡통! 싸우기 전에 하나만 묻자!","JPN":"おい、ボロ缶！　戦う前に一つ聞く！","ENG":"Hey, tin bucket! Let me ask you something before we start fighting again!","TWN":"喂，廢鐵！開戰之前，讓我問你個問題吧！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"의문. 무엇입니까?","JPN":"疑問。何でしょう？","ENG":"Question. What may it be?","TWN":"提問。什麼問題？"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"네놈들 마음에 들어서 그 잘난 선별인가 뭔가에서 뽑혔다고 치자!","JPN":"おまえらに気に入られて、そのけったいな選別か何かに選ばれたとしよう！","ENG":"Let's just say that I pass this test because you prefer to me!","TWN":"假設被你們選中進入了那什麼很了不起的計畫！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"근데 이 함선에 살아있는 인간은 단 한 명도 없었거든! 뭔가 이상한 거 아니야?","JPN":"でも、この艦船に生きている人間はたったの一人もいなかった！　何かおかしくないか？","ENG":"But I don't see any other human being on board! Isn't that weird?","TWN":"但艦船上一個活人都沒有！這也太奇怪了吧？"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"응답. 함 내 충분한 공간 확보를 위해 생존에 불필요한 신체는 절단합니다.","JPN":"応答。艦内の空間を十分確保するため、生存に不要な身体は切断します。","ENG":"Answer. To secure enough space within the fleet all body parts unnecessary for survival are severed.","TWN":"回答。為了確保艦船內有足夠空間，將對不必要的身體組織進行切除。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"그 후 항해가 끝날때까지, 냉동수면으로 가사상태를 유지.","JPN":"その後、航海が終わるまで冷凍保存し仮死状態を維持。","ENG":"Afterward, until the voyage ends, they will be put into a cryogenic sleep.","TWN":"之後，使用冷凍休眠技術進入假死狀態，直至航程結束。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"인류를 <color=#ffd34c>보존</color>합니다.","JPN":"人類を<color=#ffd34c>保存</color>します。","ENG":"Humanity is <color=#ffd34c>preserved</color>.","TWN":"如此，人類得以<color=#ffd34c>保存</color>。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 너희는 존재해서는 안 돼.","JPN":"やっぱりおまえらは存在してはいけない。","ENG":"Just as I thought. You shouldn't exist.","TWN":"果然，不能留你們。"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"덤비라고. 반드시 네놈들을 지표면에 처박아 버릴 테니까……!!","JPN":"かかってこい。絶対てめえらを地面に打ち込んでやるからな……！！","ENG":"Come at me. I'll ram you into the ground...!!","TWN":"來啊。我會把你們狠狠砸到地上……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};